package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

class CSVFormatTest {

    @Test
    void testGetAutoFlush_DefaultInstance() throws Exception {
        // Use reflection to call getAutoFlush() since it might be package-private or not accessible
        Method method = CSVFormat.class.getDeclaredMethod("getAutoFlush");
        method.setAccessible(true);
        boolean autoFlush = (boolean) method.invoke(CSVFormat.DEFAULT);
        assertFalse(autoFlush);
    }

    @Test
    void testGetAutoFlush_CustomInstanceTrue() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(true);
        Method method = CSVFormat.class.getDeclaredMethod("getAutoFlush");
        method.setAccessible(true);
        boolean autoFlush = (boolean) method.invoke(format);
        assertTrue(autoFlush);
    }

    @Test
    void testGetAutoFlush_CustomInstanceFalse() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withAutoFlush(false);
        Method method = CSVFormat.class.getDeclaredMethod("getAutoFlush");
        method.setAccessible(true);
        boolean autoFlush = (boolean) method.invoke(format);
        assertFalse(autoFlush);
    }
}
